{
  "sentences": [
    {
      "text": "我從早上八點工作到下午五點。",
      "pinyin": "Wǒ cóng zǎoshang bā diǎn gōngzuò dào xiàwǔ wǔ diǎn.",
      "pinyin_numeric": "wo3 cong2 zao3shang4 ba1 dian3 gong1zuo4 dao4 xia4wu3 wu3 dian3",
      "translation_en": "I work from 8 AM to 5 PM.",
      "translation_ko": "저는 아침 8시부터 오후 5시까지 일합니다."
    },
    {
      "text": "他從台北坐火車到高雄。",
      "pinyin": "Tā cóng Táiběi zuò huǒchē dào Gāoxióng.",
      "pinyin_numeric": "ta1 cong2 Tai2bei3 zuo4 huo3che1 dao4 Gao1xiong2",
      "translation_en": "He takes the train from Taipei to Kaohsiung.",
      "translation_ko": "그는 타이베이에서 가오슝까지 기차를 탑니다."
    },
    {
      "text": "我們從星期一到星期五都有課。",
      "pinyin": "Wǒmen cóng xīngqī yī dào xīngqī wǔ dōu yǒu kè.",
      "pinyin_numeric": "wo3men cong2 xing1qi1 yi1 dao4 xing1qi1 wu3 dou1 you3 ke4",
      "translation_en": "We have classes from Monday to Friday.",
      "translation_ko": "우리는 월요일부터 금요일까지 수업이 있습니다."
    },
    {
      "text": "你從哪裡來？",
      "pinyin": "Nǐ cóng nǎlǐ lái?",
      "pinyin_numeric": "ni3 cong2 na3li3 lai2",
      "translation_en": "Where are you from?",
      "translation_ko": "어디에서 오셨습니까?"
    },
    {
      "text": "我從圖書館走到車站。",
      "pinyin": "Wǒ cóng túshūguǎn zǒu dào chēzhàn.",
      "pinyin_numeric": "wo3 cong2 tu2shu1guan3 zou3 dao4 che1zhan4",
      "translation_en": "I walk from the library to the station.",
      "translation_ko": "저는 도서관에서 역까지 걸어갑니다."
    },
    {
      "text": "他從昨天開始不舒服。",
      "pinyin": "Tā cóng zuótiān kāishǐ bù shūfu.",
      "pinyin_numeric": "ta1 cong2 zuo2tian1 kai1shi3 bu4 shu1fu5",
      "translation_en": "He has been feeling unwell since yesterday.",
      "translation_ko": "그는 어제부터 몸이 좋지 않습니다."
    },
    {
      "text": "我們從早上到下午都在公園散步。",
      "pinyin": "Wǒmen cóng zǎoshang dào xiàwǔ dōu zài gōngyuán sànbù.",
      "pinyin_numeric": "wo3men cong2 zao3shang4 dao4 xia4wu3 dou1 zai4 gong1yuan2 san4bu4",
      "translation_en": "We take a walk in the park from morning to afternoon.",
      "translation_ko": "우리는 아침부터 오후까지 공원에서 산책합니다."
    },
    {
      "text": "你從幾點到幾點有空？",
      "pinyin": "Nǐ cóng jǐ diǎn dào jǐ diǎn yǒu kòng?",
      "pinyin_numeric": "ni3 cong2 ji3 dian3 dao4 ji3 dian3 you3 kong4",
      "translation_en": "From what time to what time are you free?",
      "translation_ko": "몇 시부터 몇 시까지 시간이 있습니까?"
    },
    {
      "text": "我從公司到醫院需要三十分鐘。",
      "pinyin": "Wǒ cóng gōngsī dào yīyuàn xūyào sānshí fēnzhōng.",
      "pinyin_numeric": "wo3 cong2 gong1si1 dao4 yi1yuan4 xu1yao4 san1shi2 fen1zhong1",
      "translation_en": "It takes thirty minutes from my company to the hospital.",
      "translation_ko": "회사에서 병원까지 30분이 걸립니다."
    },
    {
      "text": "他從上個月開始學中文。",
      "pinyin": "Tā cóng shàng ge yuè kāishǐ xué Zhōngwén.",
      "pinyin_numeric": "ta1 cong2 shang4 ge5 yue4 kai1shi3 xue2 Zhong1wen2",
      "translation_en": "He started learning Chinese last month.",
      "translation_ko": "그는 지난달부터 중국어를 배우기 시작했습니다."
    }
  ]
}
